import React from 'react';

export function StarDisplay({ rating = 0, count, size = 14 }) {
  return (
    <span className="stars" style={{ fontSize: size }}>
      {[1, 2, 3, 4, 5].map(i => (
        <span key={i} className={`star ${i <= Math.round(rating) ? '' : 'empty'}`}>★</span>
      ))}
      {count !== undefined && (
        <span style={{ fontSize: size - 2, color: 'var(--text-muted)', marginLeft: 4 }}>({count})</span>
      )}
    </span>
  );
}

export function StarInput({ value, onChange }) {
  const [hovered, setHovered] = React.useState(0);
  return (
    <div className="rating-input">
      {[1, 2, 3, 4, 5].map(i => (
        <button key={i} type="button" className={`star-btn ${i <= (hovered || value) ? 'active' : ''}`}
          onMouseEnter={() => setHovered(i)}
          onMouseLeave={() => setHovered(0)}
          onClick={() => onChange(i)}>★</button>
      ))}
    </div>
  );
}
